#[cfg(not(target_arch = "wasm32"))]
pub use model::NativeLlamaPipeline;

// On wasm32 the JS-callable pipeline lives in `wasm_bindings::WasmLlamaPipeline`
// (a `#[wasm_bindgen]` wrapper around `NativeLlamaPipeline`). The Rust-side
// host-driven pipeline is still reachable as `model::NativeLlamaPipeline` for
// any in-crate code that wants to bypass the JS boundary.
#[cfg(target_arch = "wasm32")]
pub mod wasm_bindings;

// RWKV-7 (SSM) JS-callable surface — `WasmRwkv7Pipeline` wraps the linear-time
// recurrent `model_rwkv7::RWKV7Pipeline` with an O(1) constant-size checkpoint
// (`snapshot_state` / `restore_state`). Gated behind the `ssm-wasm` feature so
// the default wasm build (the live transformer artifact) is byte-for-byte
// unchanged; build the SSM artifact separately with `--features ssm-wasm`.
#[cfg(all(target_arch = "wasm32", feature = "ssm-wasm"))]
pub mod wasm_bindings_ssm;

// Pneuma TTS JS-callable surface — `WasmPneumaTtsPipeline` wraps
// `TtsAcousticModel + HiFiGANVocoder` and exposes
// `synthesize_from_phonemes(ids) -> Vec<f32>` to the
// `pneuma-station` `/tts/phonemes` route.
#[cfg(target_arch = "wasm32")]
pub mod wasm_bindings_tts;

// Pneuma (voice / Whisper) JS-callable + NAPI surface.
//
// Mirrors `wasm_bindings::WasmLlamaPipeline` for the speech-to-text
// pipeline. Inner items are target-gated:
//   - `WasmWhisperPipeline` is `#[wasm_bindgen]`, gated on wasm32.
//   - `WhisperPipeline` (NAPI wrapper) is gated on the `napi` feature
//     plus a non-wasm target.
// The module itself compiles on all targets so external callers can
// `use distributed_inference::wasm_bindings_whisper::*` regardless of
// build profile.
pub mod wasm_bindings_whisper;

